import{_ as a,p as e,q as l,Y as i}from"./framework-aa5c4115.js";const r={},n=i('<h1 id="lerna" tabindex="-1"><a class="header-anchor" href="#lerna" aria-hidden="true">#</a> lerna</h1><h2 id="lerna简介" tabindex="-1"><a class="header-anchor" href="#lerna简介" aria-hidden="true">#</a> lerna简介</h2><p>lerna是一个基于git+npm的多package项目的管理工具。</p><h3 id="原生脚手架开发痛点" tabindex="-1"><a class="header-anchor" href="#原生脚手架开发痛点" aria-hidden="true">#</a> 原生脚手架开发痛点</h3><ul><li><p>痛点一：重复操作</p><ul><li>多Package本地link</li><li>多Package依赖安装</li><li>多Package单元测试</li><li>多Package代码提交</li><li>多Package代码发布</li></ul></li><li><p>痛点二：版本—致性</p><ul><li>发布时版本—致性</li><li>发布后相互依赖版本升级</li></ul></li></ul><blockquote><p>package越多，管理复杂度越高</p></blockquote><h3 id="lerna-优势" tabindex="-1"><a class="header-anchor" href="#lerna-优势" aria-hidden="true">#</a> lerna 优势</h3><ul><li>大幅减少重复操作</li><li>提升操作的标准化</li></ul><blockquote><p>lerna 是架构优化的产物，它揭示了一个架构真理：项目复杂度提升后，就需要对项目进行架构优化。架构优化的主要目标往往都是以效能为核心。</p></blockquote>',9),c=[n];function t(h,d){return e(),l("div",null,c)}const s=a(r,[["render",t],["__file","lerna.html.vue"]]);export{s as default};
